"use client"

import * as React from "react"
import { Accordion as AccordionPrimitive } from "radix-ui"
import { ChevronDownIcon } from "lucide-react"
import { motion, AnimatePresence } from "motion/react"

import { cn } from "@/lib/utils"

type AccordionSingleProps = React.ComponentProps<
  typeof AccordionPrimitive.Root
> & {
  type: "single"
  collapsible?: boolean
}

type AccordionMultipleProps = React.ComponentProps<
  typeof AccordionPrimitive.Root
> & {
  type: "multiple"
}

type AccordionProps = (AccordionSingleProps | AccordionMultipleProps) & {
  dividerColor?: string
  dividerWeight?: number
  dividerEnabled?: boolean
  paddingH?: number
  paddingW?: number
  spacing?: number
}

function Accordion({
  className,
  style,
  children,
  dividerColor,
  dividerWeight = 1,
  dividerEnabled = true,
  paddingH,
  paddingW,
  spacing = 0,
  ...props
}: AccordionProps) {
  const mergedStyle: React.CSSProperties = {
    ...style,
    ...(dividerColor ? { ['--accordion-divider-color' as string]: dividerColor } : {}),
    ...(dividerWeight !== undefined ? { ['--accordion-divider-weight' as string]: `${dividerWeight}px` } : {}),
    ...(paddingH !== undefined ? { ['--accordion-padding-h' as string]: `${paddingH}px` } : {}),
    ...(paddingW !== undefined ? { ['--accordion-padding-w' as string]: `${paddingW}px` } : {}),
  };

  return (
    <AccordionPrimitive.Root
      data-slot="accordion"
      data-divider={dividerEnabled ? "true" : "false"}
      className={cn("w-full", className)}
      style={mergedStyle}
      {...(props as React.ComponentProps<typeof AccordionPrimitive.Root>)}
    >
      {spacing > 0 ? (
        <div style={{ display: 'flex', flexDirection: 'column', gap: `${spacing}px` }}>
          {children}
        </div>
      ) : children}
    </AccordionPrimitive.Root>
  )
}

function AccordionItem({
  className,
  ...props
}: React.ComponentProps<typeof AccordionPrimitive.Item>) {
  return (
    <AccordionPrimitive.Item
      data-slot="accordion-item"
      className={cn(
        "group/accordion-item",
        "border-b border-[var(--accordion-divider-color,var(--border))] [border-bottom-width:var(--accordion-divider-weight,1px)] [[data-divider=false]_&]:border-0",
        "last:border-b-0",
        className
      )}
      {...props}
    />
  )
}

function AccordionTrigger({
  className,
  children,
  triggerStyle,
  ...props
}: React.ComponentProps<typeof AccordionPrimitive.Trigger> & { triggerStyle?: React.CSSProperties }) {
  return (
    <AccordionPrimitive.Header data-slot="accordion-header" className="flex">
      <AccordionPrimitive.Trigger
        data-slot="accordion-trigger"
        className={cn(
          "focus-visible:border-ring focus-visible:ring-ring/50 flex flex-1 items-center justify-between gap-4 rounded-md text-left transition-all outline-none focus-visible:ring-[3px] disabled:pointer-events-none disabled:opacity-50 [&_svg]:pointer-events-none [&_svg]:shrink-0 [&_svg:not([class*='size-'])]:size-4",
          className
        )}
        style={{
          paddingTop: 'var(--accordion-padding-h, 16px)',
          paddingBottom: 'var(--accordion-padding-h, 16px)',
          paddingLeft: 'var(--accordion-padding-w, 16px)',
          paddingRight: 'var(--accordion-padding-w, 16px)',
          ...triggerStyle,
        }}
        {...props}
      >
        {children}
        <ChevronDownIcon className="text-muted-foreground size-4 shrink-0 transition-transform duration-200 group-data-[state=open]/accordion-item:rotate-180" />
      </AccordionPrimitive.Trigger>
    </AccordionPrimitive.Header>
  )
}

function AccordionContent({
  className,
  children,
  contentStyle,
  ...props
}: React.ComponentProps<typeof AccordionPrimitive.Content> & { contentStyle?: React.CSSProperties }) {
  return (
    <AccordionPrimitive.Content
      data-slot="accordion-content"
      className="overflow-hidden"
      {...props}
    >
      <AnimatePresence initial={false}>
        <motion.div
          initial={{ height: 0, opacity: 0 }}
          animate={{ height: "auto", opacity: 1 }}
          exit={{ height: 0, opacity: 0 }}
          transition={{ type: "spring", stiffness: 400, damping: 30 }}
        >
          <div
            className={cn("pt-0", className)}
            style={{
              paddingBottom: 'var(--accordion-padding-h, 16px)',
              paddingLeft: 'var(--accordion-padding-w, 16px)',
              paddingRight: 'var(--accordion-padding-w, 16px)',
              ...contentStyle,
            }}
          >
            {children}
          </div>
        </motion.div>
      </AnimatePresence>
    </AccordionPrimitive.Content>
  )
}

export {
  Accordion,
  AccordionItem,
  AccordionTrigger,
  AccordionContent,
}
export type { AccordionProps }

import * as React from "react"
import { cva, type VariantProps } from "class-variance-authority"
import {
  InfoIcon,
  CircleCheckIcon,
  TriangleAlertIcon,
  CircleXIcon,
  XIcon,
} from "lucide-react"

import { cn } from "@/lib/utils"

const alertVariants = cva(
  "relative flex w-full gap-3 rounded-lg border p-4 [&>svg]:shrink-0 [&>svg]:size-5 [&>svg]:mt-0.5",
  {
    variants: {
      variant: {
        default:
          "border-border bg-card text-card-foreground [&>svg]:text-muted-foreground",
        info: "border-blue-200 bg-blue-50 text-blue-900 [&>svg]:text-blue-600 dark:border-blue-800 dark:bg-blue-950/50 dark:text-blue-100 dark:[&>svg]:text-blue-400",
        success:
          "border-green-200 bg-green-50 text-green-900 [&>svg]:text-green-600 dark:border-green-800 dark:bg-green-950/50 dark:text-green-100 dark:[&>svg]:text-green-400",
        warning:
          "border-amber-200 bg-amber-50 text-amber-900 [&>svg]:text-amber-600 dark:border-amber-800 dark:bg-amber-950/50 dark:text-amber-100 dark:[&>svg]:text-amber-400",
        error:
          "border-red-200 bg-red-50 text-red-900 [&>svg]:text-red-600 dark:border-red-800 dark:bg-red-950/50 dark:text-red-100 dark:[&>svg]:text-red-400",
      },
    },
    defaultVariants: {
      variant: "info",
    },
  }
)

const variantIcons = {
  default: InfoIcon,
  info: InfoIcon,
  success: CircleCheckIcon,
  warning: TriangleAlertIcon,
  error: CircleXIcon,
} as const

interface AlertProps
  extends React.ComponentProps<"div">,
    VariantProps<typeof alertVariants> {
  dismissible?: boolean
  showIcon?: boolean
  icon?: React.ReactNode
  onDismiss?: () => void
}

function Alert({
  className,
  variant = "info",
  dismissible = false,
  showIcon = true,
  icon,
  onDismiss,
  children,
  ...props
}: AlertProps) {
  const [visible, setVisible] = React.useState(true)
  const Icon = variantIcons[variant ?? "info"]

  if (!visible) return null

  return (
    <div
      data-slot="alert"
      data-variant={variant}
      role="alert"
      className={cn(alertVariants({ variant }), !showIcon && "gap-0", className)}
      {...props}
    >
      {showIcon ? (icon ?? <Icon />) : null}
      <div data-slot="alert-content" className="flex-1 space-y-1">
        {children}
      </div>
      {dismissible && (
        <button
          data-slot="alert-close"
          type="button"
          onClick={() => {
            setVisible(false)
            onDismiss?.()
          }}
          className="inline-flex shrink-0 items-center justify-center rounded-md p-0.5 opacity-70 transition-opacity duration-150 hover:opacity-100 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring"
          aria-label="Dismiss"
        >
          <XIcon className="size-4" />
        </button>
      )}
    </div>
  )
}

function AlertTitle({
  className,
  ...props
}: React.ComponentProps<"h5">) {
  return (
    <h5
      data-slot="alert-title"
      className={cn("font-semibold leading-none tracking-tight", className)}
      {...props}
    />
  )
}

function AlertDescription({
  className,
  ...props
}: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="alert-description"
      className={cn("text-sm [&_p]:leading-relaxed opacity-90", className)}
      {...props}
    />
  )
}

function AlertAction({
  className,
  ...props
}: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="alert-action"
      className={cn("mt-2 flex flex-wrap items-center gap-1.5", className)}
      {...props}
    />
  )
}

export { Alert, AlertTitle, AlertDescription, AlertAction, alertVariants }

import * as React from "react"
import { Avatar as AvatarPrimitive } from "radix-ui"

import { cn } from "@/lib/utils"

interface AvatarProps extends React.ComponentProps<typeof AvatarPrimitive.Root> {
  shape?: "circle" | "rounded"
  size?: "sm" | "md" | "lg"
  badge?: boolean
  badgeColor?: string
  customSize?: number
  radius?: number
  bgColor?: string
  bgGradientTo?: string
  bgMode?: "solid" | "gradient"
  bgOpacity?: number
  strokeWeight?: number
  strokeColor?: string
  strokeOpacity?: number
}

function Avatar({
  className,
  shape = "circle",
  size = "md",
  badge = false,
  badgeColor = "bg-green-500",
  customSize,
  radius,
  bgColor,
  bgGradientTo,
  bgMode = "solid",
  bgOpacity,
  strokeWeight,
  strokeColor,
  strokeOpacity,
  children,
  style,
  ...props
}: AvatarProps) {
  const resolvedSize = customSize ?? (size === "sm" ? 32 : size === "lg" ? 56 : 40)
  const resolvedRadius = radius ?? (shape === "circle" ? 999 : 8)

  const bgAlpha = bgOpacity !== undefined ? bgOpacity / 100 : 1
  const background = bgColor
    ? bgMode === "gradient" && bgGradientTo
      ? `linear-gradient(135deg, ${hexToRgba(bgColor, bgAlpha)} 0%, ${hexToRgba(bgGradientTo, bgAlpha)} 100%)`
      : hexToRgba(bgColor, bgAlpha)
    : undefined

  const borderStyle: React.CSSProperties = strokeWeight && strokeWeight > 0
    ? {
        borderWidth: strokeWeight,
        borderStyle: "solid",
        borderColor: strokeColor
          ? hexToRgba(strokeColor, strokeOpacity !== undefined ? strokeOpacity / 100 : 1)
          : undefined,
      }
    : {}

  const mergedStyle: React.CSSProperties = {
    width: resolvedSize,
    height: resolvedSize,
    borderRadius: resolvedRadius,
    ...(background ? { background } : {}),
    ...borderStyle,
    ...style,
  }

  return (
    <AvatarPrimitive.Root
      data-slot="avatar"
      data-shape={shape}
      data-size={size}
      className={cn("relative inline-flex shrink-0 items-center justify-center", className)}
      style={mergedStyle}
      {...props}
    >
      <div className="absolute inset-0 overflow-hidden" style={{ borderRadius: "inherit" }}>
        {children}
      </div>
      {badge && (
        <span
          data-slot="avatar-badge"
          className={cn(
            "absolute bottom-0 right-0 z-10 block rounded-full ring-2 ring-background",
            typeof badgeColor === "string" && badgeColor.startsWith("#") ? "" : badgeColor,
          )}
          style={{
            width: resolvedSize * 0.2,
            height: resolvedSize * 0.2,
            ...(typeof badgeColor === "string" && badgeColor.startsWith("#") ? { backgroundColor: badgeColor } : {}),
          }}
        />
      )}
    </AvatarPrimitive.Root>
  )
}

function AvatarImage({
  className,
  style,
  imageOpacity,
  overlayColor,
  overlayOpacity,
  ...props
}: React.ComponentProps<typeof AvatarPrimitive.Image> & {
  imageOpacity?: number
  overlayColor?: string
  overlayOpacity?: number
}) {
  const hasOverlay = overlayColor && overlayOpacity && overlayOpacity > 0

  return (
    <>
      <AvatarPrimitive.Image
        data-slot="avatar-image"
        className={cn("aspect-square size-full object-cover", className)}
        style={{
          ...style,
          ...(imageOpacity !== undefined && imageOpacity < 100 ? { opacity: imageOpacity / 100 } : {}),
        }}
        {...props}
      />
      {hasOverlay && (
        <div
          className="pointer-events-none absolute inset-0"
          style={{
            background: hexToRgba(overlayColor, overlayOpacity / 100),
            borderRadius: "inherit",
          }}
        />
      )}
    </>
  )
}

function AvatarFallback({
  className,
  style,
  fontFamily,
  fontSize,
  fontColor,
  fontBold,
  fontItalic,
  fontUnderline,
  ...props
}: React.ComponentProps<typeof AvatarPrimitive.Fallback> & {
  fontFamily?: string
  fontSize?: number
  fontColor?: string
  fontBold?: boolean
  fontItalic?: boolean
  fontUnderline?: boolean
}) {
  const typoStyle: React.CSSProperties = {
    ...(fontFamily ? { fontFamily } : {}),
    ...(fontSize ? { fontSize } : {}),
    ...(fontColor ? { color: fontColor } : {}),
    ...(fontBold ? { fontWeight: 700 } : {}),
    ...(fontItalic ? { fontStyle: "italic" } : {}),
    ...(fontUnderline ? { textDecoration: "underline" } : {}),
    ...style,
  }

  return (
    <AvatarPrimitive.Fallback
      data-slot="avatar-fallback"
      className={cn(
        "flex size-full items-center justify-center font-medium select-none",
        className
      )}
      style={typoStyle}
      {...props}
    />
  )
}

function AvatarGroup({
  className,
  spacing = -8,
  style,
  ...props
}: React.ComponentProps<"div"> & { spacing?: number }) {
  return (
    <div
      data-slot="avatar-group"
      className={cn("flex items-center [&>*+*]:ml-[var(--avatar-group-spacing)]", className)}
      style={{
        "--avatar-group-spacing": `${spacing}px`,
        ...style,
      } as React.CSSProperties}
      {...props}
    />
  )
}

function AvatarGroupCount({
  className,
  size = 40,
  radius = 999,
  bgColor,
  fontColor,
  fontSize,
  ...props
}: React.ComponentProps<"div"> & {
  size?: number
  radius?: number
  bgColor?: string
  fontColor?: string
  fontSize?: number
}) {
  return (
    <div
      data-slot="avatar-group-count"
      className={cn(
        "relative flex shrink-0 items-center justify-center font-medium ring-2 ring-background select-none",
        className
      )}
      style={{
        width: size,
        height: size,
        borderRadius: radius,
        background: bgColor || "var(--muted)",
        color: fontColor || "var(--muted-foreground)",
        fontSize: fontSize || size * 0.35,
      }}
      {...props}
    />
  )
}

// Utility — inline hex→rgba
function hexToRgba(hex: string, alpha: number): string {
  const h = hex.replace("#", "")
  const r = parseInt(h.substring(0, 2), 16)
  const g = parseInt(h.substring(2, 4), 16)
  const b = parseInt(h.substring(4, 6), 16)
  if (isNaN(r) || isNaN(g) || isNaN(b)) return hex
  return `rgba(${r},${g},${b},${alpha})`
}

export { Avatar, AvatarImage, AvatarFallback, AvatarGroup, AvatarGroupCount }

import * as React from "react"
import { cva, type VariantProps } from "class-variance-authority"
import { Slot } from "radix-ui"

import { cn } from "@/lib/utils"

const badgeVariants = cva(
  "inline-flex items-center justify-center rounded-sm border border-transparent px-2 py-0.5 w-fit whitespace-nowrap shrink-0 [&>svg]:size-3 gap-1 [&>svg]:pointer-events-none focus-visible:border-ring focus-visible:ring-ring/50 focus-visible:ring-[3px] aria-invalid:ring-destructive/20 dark:aria-invalid:ring-destructive/40 aria-invalid:border-destructive transition-[color,box-shadow] overflow-hidden",
  {
    variants: {
      variant: {
        default: "bg-primary text-primary-foreground [a&]:hover:bg-primary/90",
        secondary:
          "bg-secondary text-secondary-foreground [a&]:hover:bg-secondary/90",
        destructive:
          "bg-destructive text-white [a&]:hover:bg-destructive/90 focus-visible:ring-destructive/20 dark:focus-visible:ring-destructive/40 dark:bg-destructive/60",
        outline:
          "border-border text-foreground [a&]:hover:bg-accent [a&]:hover:text-accent-foreground",
        ghost: "[a&]:hover:bg-accent [a&]:hover:text-accent-foreground",
        link: "text-primary underline-offset-4 [a&]:hover:underline",
      },
    },
    defaultVariants: {
      variant: "default",
    },
  }
)

function Badge({
  className,
  variant = "default",
  asChild = false,
  ...props
}: React.ComponentProps<"span"> &
  VariantProps<typeof badgeVariants> & { asChild?: boolean }) {
  const Comp = asChild ? Slot.Root : "span"

  return (
    <Comp
      data-slot="badge"
      data-variant={variant}
      className={cn(badgeVariants({ variant }), className)}
      {...props}
    />
  )
}

export { Badge, badgeVariants }

import * as React from "react"
import { cva, type VariantProps } from "class-variance-authority"
import { Slot } from "radix-ui"

import { cn } from "@/lib/utils"

const buttonVariants = cva(
  "inline-flex items-center justify-center gap-2 whitespace-nowrap rounded-md transition-all disabled:pointer-events-none disabled:opacity-50 [&_svg]:pointer-events-none [&_svg:not([class*='size-'])]:size-4 shrink-0 [&_svg]:shrink-0 outline-none focus-visible:border-ring focus-visible:ring-ring/50 focus-visible:ring-[3px] aria-invalid:ring-destructive/20 dark:aria-invalid:ring-destructive/40 aria-invalid:border-destructive",
  {
    variants: {
      variant: {
        default: "bg-primary text-primary-foreground hover:bg-primary/90",
        destructive:
          "bg-destructive text-white hover:bg-destructive/90 focus-visible:ring-destructive/20 dark:focus-visible:ring-destructive/40 dark:bg-destructive/60",
        outline:
          "border bg-background shadow-xs hover:bg-accent hover:text-accent-foreground dark:bg-input/30 dark:border-input dark:hover:bg-input/50",
        secondary:
          "bg-secondary text-secondary-foreground hover:bg-secondary/80",
        ghost:
          "hover:bg-accent hover:text-accent-foreground dark:hover:bg-accent/50",
        link: "text-primary underline-offset-4 hover:underline",
      },
      size: {
        default: "h-9 px-4 py-2 has-[>svg]:px-3",
        xs: "h-6 gap-1 rounded-md px-2 text-xs has-[>svg]:px-1.5 [&_svg:not([class*='size-'])]:size-3",
        sm: "h-8 rounded-md gap-1.5 px-3 has-[>svg]:px-2.5",
        lg: "h-10 rounded-md px-6 has-[>svg]:px-4",
        icon: "size-9",
        "icon-xs": "size-6 rounded-md [&_svg:not([class*='size-'])]:size-3",
        "icon-sm": "size-8",
        "icon-lg": "size-10",
      },
    },
    defaultVariants: {
      variant: "default",
      size: "default",
    },
  }
)

function Button({
  className,
  variant = "default",
  size = "default",
  asChild = false,
  ...props
}: React.ComponentProps<"button"> &
  VariantProps<typeof buttonVariants> & {
    asChild?: boolean
  }) {
  const Comp = asChild ? Slot.Root : "button"

  return (
    <Comp
      data-slot="button"
      data-variant={variant}
      data-size={size}
      className={cn(buttonVariants({ variant, size, className }))}
      {...props}
    />
  )
}

export { Button, buttonVariants }

import { clsx, type ClassValue } from "clsx"
import { twMerge } from "tailwind-merge"

export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs))
}

import * as React from "react"
import { cva, type VariantProps } from "class-variance-authority"

import { cn } from "@/lib/utils"

const cardVariants = cva(
  "flex flex-col gap-6 rounded-xl py-6 shadow-sm",
  {
    variants: {
      variant: {
        default: "bg-card text-card-foreground border",
        bordered: "bg-card text-card-foreground border-2",
        elevated: "bg-card text-card-foreground border shadow-lg",
        glass: "bg-card/60 text-card-foreground border border-white/20 backdrop-blur-md",
      },
    },
    defaultVariants: {
      variant: "default",
    },
  }
)

interface CardProps extends React.ComponentProps<"div">, VariantProps<typeof cardVariants> {
  showDividers?: boolean
}

function Card({ className, variant, showDividers, ...props }: CardProps) {
  return (
    <div
      data-slot="card"
      data-variant={variant ?? "default"}
      data-dividers={showDividers ? "true" : undefined}
      className={cn(cardVariants({ variant }), className)}
      {...props}
    />
  )
}

function CardHeader({ className, ...props }: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="card-header"
      className={cn(
        "@container/card-header grid auto-rows-min grid-rows-[auto_auto] items-start gap-2 px-6 has-data-[slot=card-action]:grid-cols-[1fr_auto] [.border-b]:pb-6",
        className
      )}
      {...props}
    />
  )
}

function CardTitle({ className, ...props }: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="card-title"
      className={cn("leading-none font-semibold", className)}
      {...props}
    />
  )
}

function CardDescription({ className, ...props }: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="card-description"
      className={cn("text-muted-foreground text-sm", className)}
      {...props}
    />
  )
}

function CardAction({ className, ...props }: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="card-action"
      className={cn(
        "col-start-2 row-span-2 row-start-1 self-start justify-self-end",
        className
      )}
      {...props}
    />
  )
}

function CardContent({ className, ...props }: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="card-content"
      className={cn("px-6", className)}
      {...props}
    />
  )
}

function CardFooter({ className, ...props }: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="card-footer"
      className={cn("flex items-center px-6 [.border-t]:pt-6", className)}
      {...props}
    />
  )
}

export {
  Card,
  CardHeader,
  CardFooter,
  CardTitle,
  CardAction,
  CardDescription,
  CardContent,
  cardVariants,
}

"use client"

import * as React from "react"
import { CheckIcon } from "lucide-react"
import { Checkbox as CheckboxPrimitive } from "radix-ui"

import { cn } from "@/lib/utils"

function Checkbox({
  className,
  ...props
}: React.ComponentProps<typeof CheckboxPrimitive.Root>) {
  return (
    <CheckboxPrimitive.Root
      data-slot="checkbox"
      className={cn(
        "peer border-input dark:bg-input/30 data-[state=checked]:bg-primary data-[state=checked]:text-primary-foreground dark:data-[state=checked]:bg-primary data-[state=checked]:border-primary focus-visible:border-ring focus-visible:ring-ring/50 aria-invalid:ring-destructive/20 dark:aria-invalid:ring-destructive/40 aria-invalid:border-destructive size-4 shrink-0 rounded-[4px] border shadow-xs transition-shadow outline-none focus-visible:ring-[3px] disabled:cursor-not-allowed disabled:opacity-50",
        className
      )}
      {...props}
    >
      <CheckboxPrimitive.Indicator
        data-slot="checkbox-indicator"
        className="grid place-content-center text-current transition-none"
      >
        <CheckIcon className="size-3.5" />
      </CheckboxPrimitive.Indicator>
    </CheckboxPrimitive.Root>
  )
}

export { Checkbox }

import * as React from "react"

import { cn } from "@/lib/utils"

function Input({ className, type, ...props }: React.ComponentProps<"input">) {
  return (
    <input
      type={type}
      data-slot="input"
      className={cn(
