                <motion.span
                    key={`${char}-${i}`}
                    initial={{ opacity: 0, y: 20 }}
                    animate={{ opacity: 1, y: 0 }}
                    transition={{
                        delay: i * (stagger ?? 0.03),
                        duration: speed ?? 0.3,
                        ease: [0.2, 0.65, 0.3, 0.9],
                    }}
