// ─── Bounce (per-char spring bounce on hover) ───────────────────────────────

function BounceText({
    text, speed = 0.03, className, style,
}: Pick<AnimatedTextProps, 'text' | 'speed' | 'className' | 'style'>) {
    const chars = useMemo(() => text.split(''), [text]);

    return (
        <motion.span
            className={cn('inline-block cursor-pointer', className)}
            style={style}
            whileHover="hover"
            initial="initial"
            data-slot="animated-text"
        >
            {chars.map((char, i) => (
                <motion.span
                    key={`${char}-${i}`}
                    className="inline-block"
                    style={char === ' ' ? { whiteSpace: 'pre' } : undefined}
                    variants={{
                        initial: { y: 0, scale: 1 },
                        hover: {
                            y: -4,
                            scale: 1.2,
                            transition: {
                                type: 'spring',
                                stiffness: 300,
                                damping: 15,
                                delay: i * (speed ?? 0.03),
                            },
                        },
                    }}
                >
                    {char}
                </motion.span>
            ))}
        </motion.span>
    );
}

// ─── Bubble (proximity-based font-weight change on hover) ───────────────────

function BubbleText({
    text, className, style,
}: Pick<AnimatedTextProps, 'text' | 'className' | 'style'>) {
    const [hoveredIndex, setHoveredIndex] = useState<number | null>(null);
    const chars = useMemo(() => text.split(''), [text]);

    return (
        <span
            className={cn('inline-block cursor-pointer', className)}
            style={style}
            onMouseLeave={() => setHoveredIndex(null)}
            data-slot="animated-text"
        >
            {chars.map((char, i) => {
                const distance = hoveredIndex !== null ? Math.abs(hoveredIndex - i) : null;
                const weight = distance === 0 ? 900 : distance === 1 ? 500 : distance === 2 ? 300 : undefined;
                const opacity = distance === 0 ? 1 : distance === 1 ? 0.9 : undefined;
                return (
                    <span
                        key={`${char}-${i}`}
                        onMouseEnter={() => setHoveredIndex(i)}
                        className="inline-block transition-all duration-300 ease-in-out"
                        style={{
                            fontWeight: weight,
                            opacity,
                            ...(char === ' ' ? { whiteSpace: 'pre' as const } : {}),
                        }}
                    >
                        {char === ' ' ? '\u00A0' : char}
                    </span>
                );
            })}
        </span>
    );
}

// ─── Disperse (chars scatter on hover with transforms) ──────────────────────

const DISPERSE_TRANSFORMS = [
    { x: -0.8, y: -0.6, r: -29 },
    { x: -0.2, y: -0.4, r: -6 },
    { x: -0.05, y: 0.1, r: 12 },
    { x: -0.05, y: -0.1, r: -9 },
    { x: -0.1, y: 0.55, r: 3 },
    { x: 0, y: -0.1, r: 9 },
    { x: 0, y: 0.15, r: -12 },
    { x: 0, y: 0.15, r: -17 },
    { x: 0, y: -0.65, r: 9 },
    { x: 0.1, y: 0.4, r: 12 },
    { x: 0, y: -0.15, r: -9 },
    { x: 0.2, y: 0.15, r: 12 },
    { x: 0.8, y: 0.6, r: 20 },
];

function DisperseText({
    text, speed = 0.75, className, style,
}: Pick<AnimatedTextProps, 'text' | 'speed' | 'className' | 'style'>) {
    const [isActive, setIsActive] = useState(false);
    const chars = useMemo(() => text.split(''), [text]);

    return (
        <span
            className={cn('relative inline-flex cursor-pointer', className)}
            style={style}
            onMouseEnter={() => setIsActive(true)}
            onMouseLeave={() => setIsActive(false)}
            data-slot="animated-text"
        >
            {chars.map((char, i) => {
                const t = DISPERSE_TRANSFORMS[i % DISPERSE_TRANSFORMS.length];
                return (
                    <motion.span
                        key={`${char}-${i}`}
                        className="inline-block"
                        style={char === ' ' ? { whiteSpace: 'pre' } : undefined}
                        animate={isActive
                            ? { x: `${t.x}em`, y: `${t.y}em`, rotateZ: t.r }
                            : { x: 0, y: 0, rotateZ: 0 }
                        }
                        transition={{ duration: speed ?? 0.75, ease: [0.33, 1, 0.68, 1] }}
                    >
                        {char}
                    </motion.span>
                );
            })}
        </span>
    );
}

// ─── Pattern (CSS striped shadow text effect) ───────────────────────────────

function PatternText({
    text, className, style,
}: Pick<AnimatedTextProps, 'text' | 'className' | 'style'>) {
    return (
        <span
            data-shadow={text}
            className={cn('ui-studio-animated-text-pattern relative inline-block', className)}
            style={style}
            data-slot="animated-text"
        >
            {text}
        </span>
    );
}

// ─── Main Component ─────────────────────────────────────────────────────────

export function AnimatedText({
    text,
    variant = 'blur-in',
    speed,
    stagger,
    splitBy = 'word',
    gradientColor1,
    gradientColor2,
    trigger = 'mount',
    className,
    style,
}: AnimatedTextProps) {
    const [hoverKey, setHoverKey] = useState(0);
    const [hasHovered, setHasHovered] = useState(trigger === 'mount');
    const triggerAnimation = () => {
        setHasHovered(true);
        setHoverKey((k) => k + 1);
    };

    const wrapperProps = trigger === 'hover'
        ? {
            onMouseEnter: triggerAnimation,
            onFocus: triggerAnimation,
            onClick: triggerAnimation,
            tabIndex: 0,
            role: 'button' as const,
        }
        : {};

    // Before first hover: show static text
    if (trigger === 'hover' && !hasHovered) {
        return (
            <span {...wrapperProps} className={className} style={{ ...style, cursor: 'pointer' }} data-slot="animated-text">
                {text}
            </span>
        );
    }

    const commonProps = { text, speed, className, style };
    const animKey = trigger === 'hover' ? hoverKey : undefined;

    const content = (() => {
        switch (variant) {
            case 'typewriter':
                return <TypewriterText key={animKey} {...commonProps} />;
            case 'blur-in':
                return <BlurInText key={animKey} {...commonProps} stagger={stagger} splitBy={splitBy} />;
            case 'split-entrance':
                return <SplitEntranceText key={animKey} {...commonProps} stagger={stagger} splitBy={splitBy} />;
            case 'counting-number':
                return <CountingNumberText key={animKey} {...commonProps} />;
            case 'decrypt':
                return <DecryptText key={animKey} {...commonProps} />;
            case 'gradient-sweep':
                return <GradientSweepText key={animKey} {...commonProps} gradientColor1={gradientColor1} gradientColor2={gradientColor2} />;
            case 'shiny-text':
                return <ShinyText key={animKey} {...commonProps} gradientColor1={gradientColor1} gradientColor2={gradientColor2} />;
            case 'word-rotate':
                return <WordRotateText key={animKey} {...commonProps} />;
            case 'gradual-spacing':
                return <GradualSpacingText key={animKey} {...commonProps} stagger={stagger} />;
            case 'letters-pull-up':
                return <LettersPullUpText key={animKey} {...commonProps} stagger={stagger} />;
            case 'fade-up':
                return <FadeUpText key={animKey} {...commonProps} />;
            case 'fade-down':
                return <FadeDownText key={animKey} {...commonProps} />;
            case 'bounce':
                return <BounceText key={animKey} {...commonProps} />;
            case 'bubble':
                return <BubbleText key={animKey} {...commonProps} />;
            case 'disperse':
                return <DisperseText key={animKey} {...commonProps} />;
            case 'pattern':
                return <PatternText key={animKey} {...commonProps} />;
            default:
                return <span className={className} style={style} data-slot="animated-text">{text}</span>;
        }
    })();

    return <span {...wrapperProps}>{content}</span>;
}

'use client';

import * as React from 'react';
import { AlertTriangle, X } from 'lucide-react';
import { AnimatePresence, motion } from 'motion/react';
import { cn } from '@/lib/utils';

export type StatefulButtonState = 'idle' | 'loading' | 'success' | 'failure' | 'warning';
export type StatefulButtonResultState = Exclude<StatefulButtonState, 'idle' | 'loading'>;

interface StatefulButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
    className?: string;
    children: React.ReactNode;
    state?: StatefulButtonState;
    resultState?: StatefulButtonResultState;
    resetDelayMs?: number;
    loadingDurationMs?: number;
    loadingPosition?: 'left' | 'right';
    autoPlay?: boolean;
    autoPlayKey?: string | number;
}

export function StatefulButton({
    className,
    children,
    onClick,
    disabled,
    state,
    resultState = 'success',
    resetDelayMs = 1600,
    loadingDurationMs = 600,
    loadingPosition = 'left',
    autoPlay = false,
    autoPlayKey,
    ...buttonProps
}: StatefulButtonProps) {
    const [internalState, setInternalState] = React.useState<StatefulButtonState>('idle');
    const resetTimerRef = React.useRef<number | null>(null);
    const autoplayTokenRef = React.useRef<string | number | null>(null);

    const clearResetTimer = React.useCallback(() => {
        if (resetTimerRef.current !== null) {
            window.clearTimeout(resetTimerRef.current);
            resetTimerRef.current = null;
        }
    }, []);

    React.useEffect(() => clearResetTimer, [clearResetTimer]);

    const isControlled = state !== undefined;
    const currentState = isControlled ? state : internalState;
    const isRunning = currentState === 'loading';

    const runSequence = React.useCallback(async (nextResultState: StatefulButtonResultState) => {
        clearResetTimer();
        setInternalState('loading');
        await new Promise((resolve) => window.setTimeout(resolve, loadingDurationMs));
        setInternalState(nextResultState);
        resetTimerRef.current = window.setTimeout(() => {
            setInternalState('idle');
            resetTimerRef.current = null;
        }, resetDelayMs);
    }, [clearResetTimer, loadingDurationMs, resetDelayMs]);

    const handleClick = React.useCallback(async (event: React.MouseEvent<HTMLButtonElement>) => {
        if (disabled || isRunning) return;
        if (isControlled) {
            await onClick?.(event);
            return;
        }
        const startedAt = Date.now();
        clearResetTimer();
        setInternalState('loading');
        try {
            await onClick?.(event);
            const remainingLoadingMs = Math.max(0, loadingDurationMs - (Date.now() - startedAt));
            if (remainingLoadingMs > 0) {
                await new Promise((resolve) => window.setTimeout(resolve, remainingLoadingMs));
            }
            setInternalState(resultState);
        } catch (error) {
            const remainingLoadingMs = Math.max(0, loadingDurationMs - (Date.now() - startedAt));
            if (remainingLoadingMs > 0) {
                await new Promise((resolve) => window.setTimeout(resolve, remainingLoadingMs));
            }
            setInternalState('failure');
            throw error;
        } finally {
            resetTimerRef.current = window.setTimeout(() => {
                setInternalState('idle');
                resetTimerRef.current = null;
            }, resetDelayMs);
        }
    }, [clearResetTimer, disabled, isControlled, isRunning, loadingDurationMs, onClick, resetDelayMs, resultState]);

    React.useEffect(() => {
        if (isControlled || disabled || !autoPlay) {
            autoplayTokenRef.current = null;
            return;
        }
        const token = autoPlayKey ?? resultState;
        if (autoplayTokenRef.current === token) {
            return;
        }
        autoplayTokenRef.current = token;
        void runSequence(resultState);
    }, [autoPlay, autoPlayKey, disabled, isControlled, resultState, runSequence]);

    const {
        onDrag,
        onDragStart,
        onDragEnd,
        onAnimationStart,
        onAnimationEnd,
        ...safeButtonProps
    } = buttonProps;

    return (
        <motion.button
            layout
            layoutId="stage-button"
            disabled={disabled || isRunning}
            data-state={currentState}
            className={cn(
                'inline-flex min-w-[120px] items-center justify-center gap-2 rounded-full px-4 py-2 font-medium ring-offset-2 transition duration-200',
                className,
            )}
            onClick={handleClick}
            {...safeButtonProps}
        >
            <motion.span
                layout
                className={cn(
                    'inline-flex items-center gap-2',
                    loadingPosition === 'right' ? 'flex-row-reverse' : 'flex-row',
                )}
            >
                <ButtonStateIcon state={currentState} />
                <span>{children}</span>
            </motion.span>
        </motion.button>
    );
}

