}

function mapDialogIntentToVariant(
  intent: DialogActionIntent,
): React.ComponentProps<typeof Button>["variant"] {
  if (intent === "outline") {
    return "outline"
  }
  if (intent === "primary") {
    return "default"
  }
  if (intent === "danger") {
    return "destructive"
  }
  return "ghost"
}

