const CHART_MARGIN = 30;

function RefLabel({
  viewBox,
  value,
  color,
}: {
  viewBox?: { x?: number; y?: number };
  value: number;
  color: string;
}) {
  const x = viewBox?.x ?? 0;
  const y = viewBox?.y ?? 0;
  const w = value.toString().length * 7 + 10;
  return (
    <>
      <rect
        x={x - CHART_MARGIN}
        y={y - 8}
        width={w}
        height={16}
        fill={color}
        rx={3}
      />
      <text
        fontWeight={600}
        x={x - CHART_MARGIN + w / 2}
        y={y}
