  | 'glass'
  | 'accent-top'
  | 'accent-left'
  | 'accent-right'
  | 'accent-bottom'
  | 'bordered';

export interface MetricCardProps {
  title: string;
  value: number | string;
  subtitle?: string;
  format?: ValueFormat;
  trend?: TrendIndicator;
  variant?: CardVariant;
  accentColor?: string;
  sparkline?: {
    data: ChartDataPoint[];
    type?: 'line' | 'bar' | 'area';
  };
