                className="w-full"
                style={{ height }}
              >
                <RadialBarChart
                  data={chartData}
                  innerRadius={innerRadius}
                  outerRadius={outerRadius}
                  onMouseMove={(state: any) => {
                    if (state?.activePayload?.[0]) {
                      setActiveKey(
                        state.activePayload[0].payload.name as string,
                      );
                    }
                  }}
                  onMouseLeave={() => setActiveKey(null)}
