                  : 'w-full max-w-[320px] mx-auto',
              )}
            >
              <ChartContainer
                config={chartConfig}
                className="w-full"
                style={{ height: height + CHART_BREATHING_PX * 2 }}
              >
                <PieChart
                  onMouseLeave={() => {
                    if (leaveTimeoutRef.current !== null) {
                      window.clearTimeout(leaveTimeoutRef.current);
                    }
                    leaveTimeoutRef.current = window.setTimeout(() => {
                      setActiveIndex(null);
                      leaveTimeoutRef.current = null;
                    }, HOVER_RESET_DELAY_MS);
                  }}
                >
                  <ChartTooltip cursor={false} content={<DataTooltip />} />
                  <Pie
                    data={chartData}
                    dataKey="value"
                    nameKey="name"
                    innerRadius={innerRadius}
                    outerRadius={outerRadius}
                    cornerRadius={10}
                    paddingAngle={3}
                    stroke="none"
                    onMouseEnter={(_: any, index: number) => {
                      if (leaveTimeoutRef.current !== null) {
                        window.clearTimeout(leaveTimeoutRef.current);
                        leaveTimeoutRef.current = null;
                      }
                      setActiveIndex(index);
                    }}
                    {...{ activeIndex: activeIndex ?? -1 }}
                    activeShape={(shapeProps: SectorProps) => (
                      <Sector
                        {...shapeProps}
                        outerRadius={Number(shapeProps.outerRadius) + HOVER_EXPANSION_PX}
                      />
                    )}
                  >
                    {chartData.map((entry, i) => (
                      <Cell
                        key={i}
                        fill={entry.fill}
                        opacity={
                          activeIndex === null || activeIndex === i ? 1 : 0.3
                        }
                      />
                    ))}
                  </Pie>
                </PieChart>
              </ChartContainer>
            </div>
          </div>
        )}
      </CardContent>
    </Card>
  );
